'use server'
import { createSupabaseServerClient } from '@/lib/supabase/server'
import { supabaseAdmin } from '@/lib/supabase/admin'
import {
  createSurveySchema,
  updateSurveySchema,
  createSectionSchema,
  updateSectionSchema,
  createQuestionSchema,
  updateQuestionSchema,
  reorderSectionsSchema,
  reorderQuestionsSchema,
  mapDimensionsSchema,
  transitionStatusSchema,
} from '@/lib/validations/survey'
import type {
  Survey,
  SurveySection,
  SurveyQuestion,
  SurveyStatus,
} from '@/lib/types/survey'

// Untyped admin client — Database schema is a stub; real types generated by Supabase CLI in Phase 3
// eslint-disable-next-line @typescript-eslint/no-explicit-any
const db = supabaseAdmin as any

// ─── Transition Matrix ────────────────────────────────────────────────────────

const ALLOWED_TRANSITIONS: Record<SurveyStatus, SurveyStatus[]> = {
  draft: ['scheduled', 'open'],
  scheduled: ['open', 'draft'],
  open: ['closed'],
  closed: [],
}

// ─── Survey CRUD ──────────────────────────────────────────────────────────────

export async function createSurvey(
  input: unknown
): Promise<{ success: true; data: Survey } | { success: false; error: string }> {
  const parsed = createSurveySchema.safeParse(input)
  if (!parsed.success) {
    return { success: false, error: parsed.error.errors[0].message }
  }

  const supabase = await createSupabaseServerClient()
  const { data: { user }, error: authError } = await supabase.auth.getUser()
  if (authError || !user) {
    return { success: false, error: 'Unauthorized' }
  }

  const { data, error } = await db
    .from('surveys')
    .insert({ ...parsed.data, created_by: user.id })
    .select()
    .single()

  if (error) return { success: false, error: error.message }
  return { success: true, data: data as Survey }
}

export async function updateSurvey(
  input: unknown
): Promise<{ success: true; data: Survey } | { success: false; error: string }> {
  const parsed = updateSurveySchema.safeParse(input)
  if (!parsed.success) {
    return { success: false, error: parsed.error.errors[0].message }
  }

  const { id, ...fields } = parsed.data
  const { data, error } = await db
    .from('surveys')
    .update(fields)
    .eq('id', id)
    .select()
    .single()

  if (error) return { success: false, error: error.message }
  return { success: true, data: data as Survey }
}

// ─── Section Actions ──────────────────────────────────────────────────────────

export async function createSection(
  input: unknown
): Promise<{ success: true; data: SurveySection } | { success: false; error: string }> {
  const parsed = createSectionSchema.safeParse(input)
  if (!parsed.success) {
    return { success: false, error: parsed.error.errors[0].message }
  }

  const { count } = await db
    .from('survey_sections')
    .select('*', { count: 'exact', head: true })
    .eq('survey_id', parsed.data.survey_id)

  const { data, error } = await db
    .from('survey_sections')
    .insert({ ...parsed.data, display_order: (count ?? 0) })
    .select()
    .single()

  if (error) return { success: false, error: error.message }
  return { success: true, data: data as SurveySection }
}

