export async function reorderSections(
  input: unknown
): Promise<{ success: true } | { success: false; error: string }> {
  const parsed = reorderSectionsSchema.safeParse(input)
  if (!parsed.success) {
    return { success: false, error: parsed.error.errors[0].message }
  }

  for (const item of parsed.data.items) {
    const { error } = await db
      .from('survey_sections')
      .update({ display_order: item.display_order })
      .eq('id', item.id)
    if (error) return { success: false, error: error.message }
  }

  return { success: true }
}

// ─── Question Actions ─────────────────────────────────────────────────────────

export async function createQuestion(
  input: unknown
): Promise<{ success: true; data: SurveyQuestion } | { success: false; error: string }> {
  const parsed = createQuestionSchema.safeParse(input)
  if (!parsed.success) {
    return { success: false, error: parsed.error.errors[0].message }
  }

  const { options, ...questionFields } = parsed.data

  const { count } = await db
    .from('questions')
    .select('*', { count: 'exact', head: true })
    .eq('survey_section_id', questionFields.survey_section_id)

  const stableQuestionId = crypto.randomUUID()

  const { data: questionData, error: questionError } = await db
    .from('questions')
    .insert({
      ...questionFields,
      display_order: (count ?? 0),
      stable_question_id: stableQuestionId,
    })
    .select()
    .single()

  if (questionError) return { success: false, error: questionError.message }

  if (options && options.length > 0) {
    const { error: optionsError } = await db
      .from('question_options')
      .insert(
        options.map((opt: { text: string; display_order: number }) => ({
          question_id: (questionData as { id: string }).id,
          text: opt.text,
          display_order: opt.display_order,
        }))
      )
    if (optionsError) return { success: false, error: optionsError.message }
  }

  return { success: true, data: questionData as SurveyQuestion }
}

export async function updateQuestion(
  input: unknown
): Promise<{ success: true; data: SurveyQuestion } | { success: false; error: string }> {
  const parsed = updateQuestionSchema.safeParse(input)
  if (!parsed.success) {
    return { success: false, error: parsed.error.errors[0].message }
  }

  const { id, options, ...fields } = parsed.data
  const { data, error } = await db
    .from('questions')
    .update(fields)
    .eq('id', id)
    .select()
    .single()

  if (error) return { success: false, error: error.message }

  if (options !== undefined && id) {
    await db.from('question_options').delete().eq('question_id', id)
    if (options.length > 0) {
      await db.from('question_options').insert(
        options.map((opt: { text: string; display_order: number }) => ({
          question_id: id,
          text: opt.text,
          display_order: opt.display_order,
        }))
      )
    }
  }

  return { success: true, data: data as SurveyQuestion }
}

